 * Purchase a listed NFT.
 * @param {number|string} tokenId
 * @param {string}        priceWei  Exact price in wei (use nft.price from getNFT / getAllListedNFTs)
 * @returns {{ txHash: string }}
 */
export const buyNFT = async (tokenId, priceWei) => {
  await ensureSepolia();
  const contract = await getContract();
  const tx = await send(contract.buyNFT, [tokenId], { value: BigInt(priceWei) });
  const receipt = await tx.wait();
  return { txHash: receipt.hash };
};

/**
 * Delete a room. Only the room creator can call this.
 * @param {number|string} roomId
 * @returns {{ txHash: string }}
 */
export const deleteRoom = async (roomId) => {
  await ensureSepolia();
  const contract = await getContract();
  const tx = await send(contract.deleteRoom, [roomId]);
  const receipt = await tx.wait();
  return { txHash: receipt.hash };
};

// ─── Read functions ───────────────────────────────────────────────────────────

/**
 * Get a single room by ID.
 * @param {number|string} roomId
 * @returns {{ id, name, creator, isPrivate, createdAt, exists }}
 */
export const getRoom = async (roomId) => {
  const contract = await getContractReadOnly();
  const room = await contract.getRoom(roomId);
  return _formatRoom(room);
};

/**
 * Get all rooms.
 * @returns {Array<{ id, name, creator, isPrivate, createdAt, exists }>}
 */
export const getAllRooms = async () => {
  const contract = await getContractReadOnly();
  const rooms = await contract.getAllRooms();
  return rooms.map(_formatRoom);
};

/**
 * Get all messages in a room. Caller must be a member (uses signer).
 * @param {number|string} roomId
 * @returns {Array<{ sender, content, timestamp }>}
 */
export const getMessages = async (roomId) => {
  const contract = await getContract();
  const messages = await contract.getMessages(roomId);
  return messages.map(_formatMessage);
};

/**
 * Get private messages between two addresses. Caller must be one of them.
 * @param {string} user1
 * @param {string} user2
 * @returns {Array<{ sender, content, timestamp }>}
 */
export const getPrivateMessages = async (user1, user2) => {
  const contract = await getContract();
  const messages = await contract.getPrivateMessages(user1, user2);
  return messages.map(_formatMessage);
};

/**
 * Check if an address is a member of a room.
 * @param {number|string} roomId
 * @param {string}        address
 * @returns {boolean}
 */
export const isMember = async (roomId, address) => {
  const contract = await getContractReadOnly();
  return contract.isMember(roomId, address);
};

/**
 * Get a single NFT by token ID.
 * @param {number|string} tokenId
 * @returns {{ tokenId, owner, name, metadataURI, priceEth, priceWei, isListed }}
 */
export const getNFT = async (tokenId) => {
  const contract = await getContractReadOnly();
  const nft = await contract.getNFT(tokenId);
  return _formatNFT(nft);
};

/**
 * Get all NFTs currently listed for sale.
 * @returns {Array<{ tokenId, owner, name, metadataURI, priceEth, priceWei, isListed }>}
 */
export const getAllListedNFTs = async () => {
  const contract = await getContractReadOnly();
  const nfts = await contract.getAllListedNFTs();
  return nfts.map(_formatNFT);
};

/**
 * Get all NFTs owned by an address.
 * @param {string} ownerAddress  Defaults to connected wallet if omitted.
 * @returns {Array<{ tokenId, owner, name, metadataURI, priceEth, priceWei, isListed }>}
 */
export const getNFTsByOwner = async (ownerAddress) => {
  const address = ownerAddress ?? await getConnectedAddress();
  if (!ethers.isAddress(address)) throw new Error('Invalid address.');
  const contract = await getContractReadOnly();
  const nfts = await contract.getNFTsByOwner(address);
  return nfts.map(_formatNFT);
};

// ─── Formatters ───────────────────────────────────────────────────────────────

function _formatRoom(r) {
  return {
    id: r.id.toString(),
    name: r.name,
    creator: r.creator,
    isPrivate: r.isPrivate,
    createdAt: new Date(Number(r.createdAt) * 1000).toISOString(),
    exists: r.exists,
  };
}

function _formatMessage(m) {
  return {
    sender: m.sender,
    content: m.content,
    timestamp: new Date(Number(m.timestamp) * 1000).toISOString(),
  };
}

function _formatNFT(n) {
  return {
    tokenId: n.tokenId.toString(),
    owner: n.owner,
    name: n.name,
    metadataURI: n.metadataURI,
    priceWei: n.price.toString(),
    priceEth: ethers.formatEther(n.price),
    isListed: n.isListed,
  };
}

function _extractEvent(contract, receipt, eventName, argName) {
  try {
    for (const log of receipt.logs) {
      const parsed = contract.interface.parseLog(log);
      if (parsed?.name === eventName) return parsed.args[argName]?.toString();
    }
  } catch { /* unrelated logs will fail to parse — that's fine */ }
  return null;
}
